import { Component, OnInit } from '@angular/core';
import { DatabaseService } from '../../services/database';
import { CartService, CartItem, ExtraItem } from '../../services/cart';
import { ThemeService } from '../../services/theme';
import { AlertController } from '@ionic/angular';

@Component({
  selector: 'app-pos',
  templateUrl: './pos.page.html',
  styleUrls: ['./pos.page.scss'],
  standalone: false
})
export class PosPage implements OnInit {
  categories: any[] = [];
  products: any[] = [];
  filteredProducts: any[] = [];
  toppings: ExtraItem[] = [];
  selectedCategoryId: number | null = null;
  searchTerm: string = '';
  cartItems: CartItem[] = [];
  total: number = 0;
  tax: number = 0;
  grandTotal: number = 0;

  constructor(
    private dbService: DatabaseService,
    public cartService: CartService,
    public themeService: ThemeService,
    private alertCtrl: AlertController
  ) { }

  async ngOnInit() {
    await this.loadData();

    // Escuchar cambios en el carrito
    this.cartService.cartItems$.subscribe(() => {
      this.refreshTotals();
    });

    // Cargar IVA guardado
    const ivaConfig = await this.dbService.query("SELECT value FROM config WHERE key = 'iva'");
    if (ivaConfig.values?.length) {
      const ivaValue = parseFloat(ivaConfig.values[0].value);
      this.cartService.setIva(ivaValue);
      this.refreshTotals();
    }
  }

  refreshTotals() {
    this.total = this.cartService.getTotal();
    this.tax = this.cartService.getTax();
    this.grandTotal = this.cartService.getGrandTotal();
  }

  async loadData() {
    const catResult = await this.dbService.query('SELECT * FROM categories');
    this.categories = catResult.values || [];

    const prodResult = await this.dbService.query('SELECT * FROM products WHERE is_active = 1');
    this.products = prodResult.values || [];

    const toppingResult = await this.dbService.query('SELECT * FROM toppings');
    this.toppings = toppingResult.values || [];

    this.applyFilters();
  }

  filterByCategory(catId: number | null) {
    this.selectedCategoryId = catId;
    this.applyFilters();
  }

  onSearchChange(event: any) {
    this.searchTerm = event.detail.value;
    this.applyFilters();
  }

  applyFilters() {
    this.filteredProducts = this.products.filter(p => {
      const matchesCat = this.selectedCategoryId ? p.cat_id === this.selectedCategoryId : true;
      const matchesSearch = p.name.toLowerCase().includes(this.searchTerm.toLowerCase());
      return matchesCat && matchesSearch;
    });
  }

  async addToCartWithExtras(product: any) {
    if (this.toppings.length === 0) {
      this.cartService.addToCart(product);
      return;
    }

    const alert = await this.alertCtrl.create({
      header: 'Añadir Extras ✨',
      message: `Elige toppings para: ${product.name}`,
      inputs: this.toppings.map(e => ({
        type: 'checkbox',
        label: `${e.name} (+${e.price})`,
        value: e,
        name: e.name
      })),
      buttons: [
        { text: 'Sin extras', handler: () => this.cartService.addToCart(product) },
        { 
          text: 'Añadir', 
          handler: (extras: ExtraItem[]) => {
            this.cartService.addToCart(product, extras);
          }
        }
      ]
    });
    await alert.present();
  }

  async checkout() {
    if (this.cartItems.length === 0) return;

    const date = new Date().toISOString();
    const result = await this.dbService.run(
      'INSERT INTO orders (date, total, tax, payment_method, status) VALUES (?, ?, ?, ?, ?)',
      [date, this.grandTotal, this.tax, 'Efectivo', 'Completado']
    );

    const orderId = result.changes?.lastId;
    if (orderId) {
      for (const item of this.cartItems) {
        const extrasText = item.extras.map(e => e.name).join(', ');
        await this.dbService.run(
          'INSERT INTO order_items (order_id, product_id, qty, price, subtotal, extras_text) VALUES (?, ?, ?, ?, ?, ?)',
          [orderId, item.product_id, item.qty, item.price, item.subtotal, extrasText]
        );
      }
    }

    this.cartService.clearCart();
    const successAlert = await this.alertCtrl.create({
      header: '¡Venta Exitosa! 🍩',
      message: 'Gracias por tu compra.',
      buttons: ['OK']
    });
    await successAlert.present();
    await this.loadData();
  }

  async showConfig() {
    const alert = await this.alertCtrl.create({
      header: 'Configuración ⚙️',
      inputs: [
        {
          name: 'iva',
          type: 'number',
          placeholder: 'IVA %',
          value: this.cartService.getIvaRate()
        }
      ],
      buttons: [
        { text: 'Cancelar', role: 'cancel' },
        {
          text: 'Guardar',
          handler: async (data) => {
            const newIva = parseFloat(data.iva);
            await this.dbService.run("UPDATE config SET value = ? WHERE key = 'iva'", [newIva]);
            this.cartService.setIva(newIva);
            this.refreshTotals();
          }
        }
      ]
    });
    await alert.present();
  }
}
<ion-header>
  <ion-toolbar color="primary">
    <ion-title>DonasApp 🍩</ion-title>
    <ion-buttons slot="end">
      <ion-button (click)="themeService.toggleTheme()">
        <ion-icon [name]="themeService.isDarkMode() ? 'sunny' : 'moon'"></ion-icon>
      </ion-button>
      <ion-button (click)="showConfig()">
        <ion-icon name="settings-outline"></ion-icon>
      </ion-button>
      <ion-button routerLink="/inventory">Inventario</ion-button>
      <ion-button routerLink="/wallet">Cartera</ion-button>
    </ion-buttons>
  </ion-toolbar>
  <ion-toolbar color="light">
    <ion-searchbar (ionInput)="onSearchChange($event)" placeholder="Buscar donas..."></ion-searchbar>
  </ion-toolbar>
</ion-header>

<ion-content>
  <div class="pos-container">
    <div class="products-section">
      <div class="kawaii-header" style="text-align: left; padding-left: 10px;">🌸 Menú de Hoy 🌸</div>
      <div class="category-filters">
        <ion-chip [outline]="selectedCategoryId !== null" color="primary" (click)="filterByCategory(null)">🌈 Todas</ion-chip>
        <ion-chip *ngFor="let cat of categories" [outline]="selectedCategoryId !== cat.id" [style.--background]="cat.color_code" color="dark" (click)="filterByCategory(cat.id)">
          ✨ {{cat.name}}
        </ion-chip>
      </div>

      <ion-grid>
        <ion-row>
          <ion-col size="6" size-md="4" size-lg="3" *ngFor="let prod of filteredProducts">
            <ion-card (click)="addToCartWithExtras(prod)" class="product-card kawaii-card">
              <img [src]="prod.image_url || 'https://placehold.co/200x200?text=🍩'" />
              <ion-card-header>
                <ion-card-subtitle style="color: var(--ion-color-tertiary); font-weight: bold;">{{prod.price | currency}}</ion-card-subtitle>
                <ion-card-title style="font-size: 1.1rem;">{{prod.name}}</ion-card-title>
              </ion-card-header>
              <ion-card-content>
                Stock: {{prod.stock}} 🍭
              </ion-card-content>
            </ion-card>
          </ion-col>
        </ion-row>
      </ion-grid>
    </div>

    <div class="ticket-panel">
      <ion-card class="ticket-card kawaii-card">
        <ion-card-header>
          <ion-card-title>📝 Mi Ticket</ion-card-title>
        </ion-card-header>
        <ion-card-content>
          <ion-list>
            <ion-item *ngFor="let item of cartItems; let i = index">
              <ion-label>
                <h2>{{item.name}}</h2>
                <p *ngIf="item.extras.length">Extras: {{item.extras.length}} 🍬</p>
                <p>{{item.qty}} x {{item.price | currency}}</p>
              </ion-label>
              <ion-note slot="end">{{item.subtotal | currency}}</ion-note>
              <ion-button fill="clear" color="danger" (click)="cartService.removeFromCart(i)">
                <ion-icon name="trash-outline"></ion-icon>
              </ion-button>
            </ion-item>
          </ion-list>

          <div class="ticket-totals">
            <ion-item lines="none">
              <ion-label>Subtotal</ion-label>
              <ion-note slot="end">{{total | currency}}</ion-note>
            </ion-item>
            <ion-item lines="none">
              <ion-label>IVA ({{cartService.getIvaRate()}}%)</ion-label>
              <ion-note slot="end">{{tax | currency}}</ion-note>
            </ion-item>
            <ion-item lines="none" class="grand-total">
              <ion-label>TOTAL 🎀</ion-label>
              <ion-note slot="end" color="primary">{{grandTotal | currency}}</ion-note>
            </ion-item>
          </div>

          <ion-button expand="block" color="success" (click)="checkout()" [disabled]="cartItems.length === 0">
            PROCESAR PAGO ✨
          </ion-button>
          <ion-button expand="block" fill="clear" color="medium" (click)="cartService.clearCart()">
            CANCELAR
          </ion-button>
        </ion-card-content>
      </ion-card>
    </div>
  </div>
</ion-content>
